const body = msg.payload || {};
const command = String(body.command || '').trim();
const source = String(body.source || 'node_red').trim() || 'node_red';
const confirm = !!body.confirm;
if (!command) {
    const bad = {
        payload: { ok: false, error: 'command required' },
        statusCode: 400,
        req: msg.req,
        res: msg.res
    };
    return [null, bad];
}
const cmd = {
    command,
    source,
    confirm
};
const toMqtt = {
    topic: 'home/ai/command',
    payload: JSON.stringify(cmd)
};
const ack = {
    payload: {
        ok: true,
        queued: true,
        command,
        source,
        confirm
    },
    req: msg.req,
    res: msg.res
};
return [toMqtt, ack];

const value = flow.get('ai_last_result') || { status: 'idle', detail: 'No result yet' };
msg.headers = { 'Content-Type': 'application/json' };
msg.payload = JSON.stringify(value);
return msg;

const mode = String((msg.payload || {}).mode || '').trim().toLowerCase();
if (!['suggest', 'ask', 'auto'].includes(mode)) {
    return [null, {
        payload: { ok: false, error: 'mode must be suggest|ask|auto' },
        statusCode: 400,
        req: msg.req,
        res: msg.res
    }];
}
const out = { topic: 'home/ai/mode/set', payload: mode };
const ack = {
    payload: { ok: true, mode },
    req: msg.req,
    res: msg.res
};
return [out, ack];

